header.fixed-header>.right.auto>a.v-center {
    display: flex;
    justify-content: center;
    align-items: center;
    margin-top: 2px;
}
header.fixed-header>.right.auto>a.v-center > i.la {
    margin-top: 0;
}
.list-group-item.active:active,
.list-group-item.active:focus,
.list-group-item.active:hover {
    background-color: #0067d5
}
.list-group.list-group-compact .list-group-item {
    padding: 6px 12px;
    font-size: 14px;
    min-height: 20px;
    line-height: 20px;
}
.list-group.list-group-compact .list-group-item span[class="badge "] {
    font-size: 14px;
    line-height: 20px;
}
.dropdown-menu.show {
    max-width: 95vw;
}
div.form-group-disabled {
    pointer-events: none;
    user-select: none;
    color: #bbb !important
}
div.form-group-disabled label {
    color: #bbb !important
}
div.form-group-disabled .form-text.text-muted {
    color: #bbb !important
}
div.form-group-disabled input,
div.form-group-disabled input[type=checkbox],
div.form-group-disabled input[type=radio],
div.form-group-disabled select,
div.form-group-disabled textarea,
div.form-group-disabled a,
div.form-group-disabled .form-control {
    opacity: .35;
    user-select: none;
}
.border-less {
    border: none;
    background: transparent;
    padding-right: 0;
}
.weui-actionsheet__title-text {
    margin-bottom: 0 !important;
}
.weui-tabbar__label {
    margin-bottom: 0;
}
.weui-tabbar__icon.la,
.weui-tabbar__icon.las,
.weui-tabbar__icon.lar,
.weui-tabbar__icon.lab {
    width: auto;
    height: auto;
}
h5 > .badge {
    font-size: 10px;
    vertical-align: middle;
}
.toolstable {
    margin:8px 0 0 0 !important;
    width: 100%;
}
.toolstable td {
    width:50%;
  border: 1px solid #f5f5f5;
    padding:8px !important;
    font-size: 15px;
}
.toolstable td i{
    line-height: 14px;
    font-size: 16px;
    margin: 0 5px;
}
.form-data-list .list-group-item.list-group-header {
    font-weight: bold;
    background-color: #f6f6f6;
}
.form-data-list.form-data-list-values .list-group-item {
    align-items: center;
}
.form-data-list-values .label > .form-text {
    margin-top: 2px !important;
}
.btn-outline-append {
    border: 1px solid #ced4da;
    font-size: 20px;
    padding: 3px 8px 0;
    display: flex;
    justify-content: center;
    align-items: center;
    box-shadow: none;
}
.btn-outline-append:hover, .btn-outline-append:active {
    background-color: #ccc;
}
@keyframes toastSlideDown {
    from {
        transform: translate(-50%, -50%);
        opacity: 0;
    }
    to {
        transform: translate(-50%, 0);
        opacity: 1;
    }
}
.exam-toast {
    position: fixed;
    z-index: 999999;
    transform: translate(-50%, 0);
    font-size: 15px;
    left: 50%;
    top: 64px;
    background: var(--dark);
    color: #fff;
    padding: 8px 12px;
    border-radius: 4px;
    box-shadow: 0 0 15px rgba(0, 0, 0, 0.3);
    animation: toastSlideDown 0.3s ease-in-out;
}
header.fixed-header.with-drops {
    overflow: visible;
}
header a.dropdown-toggle {
    width: auto;
    height: auto;
    padding-left: 10px;
    padding-right: 5px;
    vertical-align: middle;
}
header .dropdown-menu a {
    width: auto;
    height: auto;
    line-height: 2.2em;
    text-align: left;
    border-radius: 0;
    margin: 0;
}
.no-bg-hover:hover {
    background-color: initial;
}
.progress > .progress-bar {
    overflow: visible;
    text-shadow: 0 0 2px #333;
}
.bjmf-card .card-body > .table-bordered {
    border: none !important;
    border-collapse: collapse !important;
}
.bjmf-card .card-body > .table-bordered td {
    border: 1px solid #f8f8f8;
    font-size: 14px;
    vertical-align: top;
}
.bjmf-card .card-body > .table-bordered td > a.d-block {
    padding: 12px !important;
    color: #333;
}
.bjmf-card .card-body > .table-bordered.table-functions td {
    padding: 12px !important;
}
.bjmf-card .card-body > .table-bordered td > a.d-block:hover,
.bjmf-card .card-body > .table-bordered td > a.d-block:active,
.bjmf-card .card-body > .table-bordered td > a.d-block:focus,
.bjmf-card .card-body > .table-bordered.table-functions td:hover,
.bjmf-card .card-body > .table-bordered.table-functions td:active,
.bjmf-card .card-body > .table-bordered.table-functions td:focus {
    background-color: #f8f8f8;
    cursor: pointer;
}
.bjmf-card .card-body > .table-bordered td i {
    color: var(--primary);
    margin-right: 5px;
    font-size: 20px;
    vertical-align: top;
    line-height: 1;
}
.badge-outline-primary {
    border: 1px solid var(--primary);
    background: white;
    color: var(--primary);
}
.badge-outline-secondary {
    border: 1px solid var(--secondary);
    background: white;
    color: var(--secondary);
}

.form-control.form-control-datepicker2[readonly], .form-control.form-control-date-picker[readonly] {
    background: #fff;
}

.glightbox-clean button.gclose {
    left: 50%;
    right: auto;
    transform: translateX(-50%);
    flex-direction: row;
    width: auto;
    color: white;
    padding: 0 10px;
}

.glightbox-clean button.gclose:after {
    content: '关闭图片';
    margin-left: 10px;
}

.blurred {
    filter: blur(3px);
}

@media screen and (max-width: 350px) {
    header.fixed-header>.left>a>i.la.la-arrow-left {
        line-height: 36px;
    }
}

@media screen and (max-width: 350px) {
    header {
        height: 44px;
    }

    header.fixed-header > .right.auto > a.outline {
        height: 26px;
        line-height: 25px;
        vertical-align: middle;
        margin-top: 7px;
    }
}
